// Extract event data from router payload
const input = $input.first().json;

// Router sends: { event_id, event_type, project_id, payload }
const eventId = input.body?.event_id || input.event_id;
const projectId = input.body?.project_id || input.project_id;
const payload = input.body?.payload || input.payload || {};

// Step key is project-specific
const stepKey = `notification:${projectId}`;

return {
  json: {
    event_id: eventId,
    project_id: projectId,
    files_synced: payload.files_synced || 0,
    project_folder_id: payload.project_folder_id,
    step_key: stepKey
  }
};

// Build Telegram message with project details
const project = $input.first().json;
const eventData = $('Parse Event Data').first().json;

// Build Drive URL
const driveUrl = eventData.project_folder_id 
  ? `https://drive.google.com/drive/folders/${eventData.project_folder_id}`
  : null;

// Format address
const address = [project.object_street, `${project.object_zip} ${project.object_city}`]
  .filter(Boolean)
  .join(', ');

// Build message lines
const lines = [
  '🏗️ *Neues Projekt angelegt*',
  '',
  `📋 *${project.project_number || 'Ohne Nummer'}*`,
  project.client_name ? `🏢 ${project.client_name}` : null,
  address ? `📍 ${address}` : null,
  '',
  driveUrl ? `📂 [Drive-Ordner öffnen](${driveUrl})` : null,
  '',
  `✅ ${eventData.files_synced} Datei(en) synchronisiert`
].filter(Boolean);

return {
  json: {
    message: lines.join('\n'),
    project_id: eventData.project_id,
    project_number: project.project_number,
    event_id: eventData.event_id,
    step_key: eventData.step_key,
    files_synced: eventData.files_synced,
    project_folder_id: eventData.project_folder_id
  }
};

parameters.query:
SELECT complete_workflow_step(
  '{{ $('Format Telegram Message').item.json.step_key }}',
  '{"notification_sent": true, "project_number": "{{ $('Format Telegram Message').item.json.project_number }}"}'
);

-- Mark input event as processed
DO $$ BEGIN
  UPDATE events SET processed_at = now() WHERE id = '{{ $('Format Telegram Message').item.json.event_id }}'::uuid;
EXCEPTION WHEN invalid_text_representation THEN NULL;
END $$;

-- Emit NOTIFICATION_SENT event (for audit trail)
INSERT INTO events (event_type, project_id, payload, source_system, source_flow)
VALUES (
  'NOTIFICATION_SENT',
  '{{ $('Format Telegram Message').item.json.project_id }}'::uuid,
  '{"channel": "telegram", "project_number": "{{ $('Format Telegram Message').item.json.project_number }}", "files_synced": {{ $('Format Telegram Message').item.json.files_synced }}}',
  'n8n',
  'M1_05_Notification'
)
RETURNING id, event_type::text, project_id;

